const getVeinType = (level) => {
  if (level <= 1) return 'copper_ore';
  if (level === 2) return 'iron_ore';
  if (level === 3) return 'wood';
  if (level === 4) return 'coal';
  if (level === 5) return 'stone';
  if (level === 6) return 'coal';
  if (level === 7) return 'copper_ore';
  if (level === 8) return 'iron_ore';
  if (level === 9) return 'coal';
  if (level === 10) return 'water';
  
  const bagContents = ['copper_ore', 'iron_ore', 'stone', 'water', 'coal', 'water', 'copper_ore', 'iron_ore', 'wood'];
  const bagSize = bagContents.length;
  const bagNumber = Math.floor((level - 11) / bagSize); 
  const itemIndex = (level - 11) % bagSize; 

  let seed = (bagNumber + 1) * 1337;
  const seededRandom = () => {
      seed = (seed * 9301 + 49297) % 233280;
      return seed / 233280;
  };

  let shuffledBag = [...bagContents];
  for (let i = shuffledBag.length - 1; i > 0; i--) {
      const j = Math.floor(seededRandom() * (i + 1));
      [shuffledBag[i], shuffledBag[j]] = [shuffledBag[j], shuffledBag[i]];
  }

  return shuffledBag[itemIndex];
};

const getRequiredPoints = (level) => {
    let scale = 1 + Math.floor((level - 1) / 10) * 0.5;
    return Math.floor(100 + (level - 1) * 50 * scale);
};

