const generateId = () => Math.random().toString(36).substr(2, 9);
const sumValues = (obj) => obj ? Object.values(obj).reduce((a, b) => a + b, 0) : 0;
const getBezierPoint = (t, p0, p1, p2, p3) => {
    const cT = 1 - t;
    return cT * cT * cT * p0 + 3 * cT * cT * t * p1 + 3 * cT * t * t * p2 + t * t * t * p3;
};

function recalcBuiltCounts(state) {
  let builtCounts = {};
  Object.values(state.nodes).forEach(n => {
    if ((n.type.startsWith('extractor') || n.type.startsWith('water_pump')) && n.resource) {
      const cost = n.type.includes('adv') ? 3 : 1;
      builtCounts[n.resource] = (builtCounts[n.resource] || 0) + cost;
    }
  });
  state.prospecting.built = builtCounts;
}

function applyGodMode(state) {
  if (state.godmode && !state.godmodeApplied) {
    state.techsUnlocked = Object.keys(TECHS);
    state.prospecting.level = 50;
    state.prospecting.points = 0;
    state.prospecting.pending = 0;
    state.prospecting.discovered = {};
    for (let i = 1; i <= 50; i++) {
      const type = getVeinType(i);
      state.prospecting.discovered[type] = (state.prospecting.discovered[type] || 0) + 1;
    }
    
    const startNode = Object.values(state.nodes).find(n => n.type === 'storage' || n.type === 'storage_adv');
    if (startNode && startNode.inventory) {
        startNode.capacity = Math.max(startNode.capacity, 100000);
        for (let res of Object.keys(RESOURCES)) {
            startNode.inventory[res] = Math.max(startNode.inventory[res] || 0, 10000);
        }
    }
    
    state.godmodeApplied = true;
  }
  return state;
}

function getNodeSpeedMultiplier(node, state, usesPower) {
    if (node.enabled === false || node.isOffline) return 0;
    let speedMult = usesPower ? state.power.ratio : 1;
    
    if (state.compute.safeMode && usesPower) {
        if (node.recipe && RECIPES[node.recipe]) {
            const outputs = RECIPES[node.recipe].outputs;
            if (outputs['red_data'] || outputs['green_data'] || outputs['blue_data']) {
                speedMult = 0; 
            } else {
                speedMult *= 0.1;
            }
        } else {
            speedMult *= 0.1;
        }
    }

    if (node.type === 'processor_adv' || node.type === 'furnace_elec') speedMult *= 2;
    if (node.type === 'furnace_adv') speedMult *= 3;
    
    return speedMult;
}

function getActiveBoosters(state) {
    let boosters = {};
    state.edges.forEach(e => {
        const fromNode = state.nodes[e.from];
        if (fromNode && fromNode.type.startsWith('booster_') && fromNode.enabled !== false && !fromNode.isOffline && fromNode.isActive) {
            if (!boosters[e.to]) boosters[e.to] = {};
            boosters[e.to][fromNode.type.split('_')[1]] = true;
        }
    });
    return boosters;
}

